import { handleRequest } from "./http/router";

export function startServer() {
  return { handle: handleRequest };
}
import { createReport } from "../reports/service";

export async function handleRequest(method: string, path: string, body: unknown) {
  if (method === "POST" && path === "/reports") {
    const report = await createReport(body);
    return { status: 202, body: report };
  }

  return { status: 404, body: { error: "not found" } };
}
import { enqueue } from "../jobs/queue";
import { insertReport } from "./repository";

type ReportInput = { accountId: string; title: string };

export async function createReport(input: unknown) {
  const report = validateReport(input);
  const stored = await insertReport(report);
  await enqueue("report.created", { reportId: stored.id, accountId: stored.accountId });
  return stored;
}

function validateReport(input: unknown): ReportInput {
  if (!input || typeof input !== "object") throw new Error("invalid report");
  const value = input as Partial<ReportInput>;
  if (!value.accountId || !value.title) throw new Error("invalid report");
  return { accountId: value.accountId, title: value.title };
}
import { database } from "../storage/database";

export async function insertReport(report: { accountId: string; title: string }) {
  return database.insert("reports", report);
}

type Job = { name: string; payload: Record<string, unknown> };

const pending: Job[] = [];

export async function enqueue(name: string, payload: Record<string, unknown>) {
  pending.push({ name, payload });
}

export function takeNextJob() {
  return pending.shift();
}
import { takeNextJob } from "./jobs/queue";
import { sendReportReady } from "./notifications/email";

export async function runOneJob() {
  const job = takeNextJob();
  if (job?.name === "report.created") {
    await sendReportReady(String(job.payload.accountId), String(job.payload.reportId));
  }
}
export async function sendReportReady(accountId: string, reportId: string) {
  return { delivered: true, accountId, reportId };
}
let nextId = 1;

export const database = {
  async insert(table: string, value: Record<string, unknown>) {
    return { id: nextId++, table, ...value };
  },
};
import { handleRequest } from "../src/http/router";
import { runOneJob } from "../src/worker";

test("creating a report returns the stored record with 202", async () => {
  const response = await handleRequest("POST", "/reports", {
    accountId: "acct-1",
    title: "Weekly",
  });

  expect(response.status).toBe(202);
  expect(response.body).toMatchObject({ accountId: "acct-1", title: "Weekly" });
});

test("the queued report-created job can be processed", async () => {
  await handleRequest("POST", "/reports", {
    accountId: "acct-1",
    title: "Weekly",
  });

  await expect(runOneJob()).resolves.toBeUndefined();
});
